:root {
  --bg: #0c0f14;
  --surface: #151a24;
  --surface-elevated: #1c2330;
  --border: rgba(255, 255, 255, 0.08);
  --text: #e8ecf4;
  --text-muted: #8b95a8;
  --accent: #f5c542;
  --accent-dim: #c9a02e;
  --bonus: #5b9cff;
  --ball-1-10: #f5c542;
  --ball-11-20: #4dabf7;
  --ball-21-30: #ff6b6b;
  --ball-31-40: #adb5bd;
  --ball-41-45: #69db7c;
  --radius: 14px;
  --shadow: 0 12px 40px rgba(0, 0, 0, 0.45);
  font-family: "Noto Sans KR", system-ui, sans-serif;
}

*,
*::before,
*::after {
  box-sizing: border-box;
}

body {
  margin: 0;
  min-height: 100vh;
  background: var(--bg);
  color: var(--text);
  line-height: 1.6;
}

.bg-glow {
  position: fixed;
  inset: 0;
  pointer-events: none;
  background:
    radial-gradient(ellipse 60% 40% at 50% -10%, rgba(245, 197, 66, 0.12), transparent),
    radial-gradient(ellipse 50% 30% at 90% 80%, rgba(91, 156, 255, 0.08), transparent);
}

.app {
  position: relative;
  max-width: 720px;
  margin: 0 auto;
  padding: 2.5rem 1.25rem 3rem;
}

.header {
  text-align: center;
  margin-bottom: 2rem;
}

.eyebrow {
  margin: 0 0 0.5rem;
  font-size: 0.75rem;
  font-weight: 500;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--accent);
}

h1 {
  margin: 0 0 0.75rem;
  font-size: clamp(1.75rem, 5vw, 2.25rem);
  font-weight: 700;
  letter-spacing: -0.02em;
}

.subtitle {
  margin: 0;
  font-size: 0.95rem;
  color: var(--text-muted);
  max-width: 36em;
  margin-inline: auto;
}

.subtitle strong {
  color: var(--text);
  font-weight: 500;
}

.subtitle em {
  font-style: normal;
  color: var(--accent);
}

.card {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 1.5rem;
  margin-bottom: 1.25rem;
  box-shadow: var(--shadow);
}

.card h2 {
  margin: 0 0 1rem;
  font-size: 1.1rem;
  font-weight: 600;
}

.draw-card {
  text-align: center;
}

.balls {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: 0.6rem;
  min-height: 3.25rem;
  margin-bottom: 1rem;
}

.ball {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 3rem;
  height: 3rem;
  border-radius: 50%;
  font-family: "JetBrains Mono", monospace;
  font-size: 1.05rem;
  font-weight: 700;
  color: #111;
  box-shadow:
    inset 0 -3px 6px rgba(0, 0, 0, 0.2),
    0 4px 12px rgba(0, 0, 0, 0.35);
  animation: pop 0.35s cubic-bezier(0.34, 1.56, 0.64, 1) backwards;
}

.ball:nth-child(1) { animation-delay: 0ms; }
.ball:nth-child(2) { animation-delay: 50ms; }
.ball:nth-child(3) { animation-delay: 100ms; }
.ball:nth-child(4) { animation-delay: 150ms; }
.ball:nth-child(5) { animation-delay: 200ms; }
.ball:nth-child(6) { animation-delay: 250ms; }

@keyframes pop {
  from {
    opacity: 0;
    transform: scale(0.4) translateY(8px);
  }
  to {
    opacity: 1;
    transform: scale(1) translateY(0);
  }
}

.ball--range-1 { background: linear-gradient(145deg, #ffe066, var(--ball-1-10)); }
.ball--range-2 { background: linear-gradient(145deg, #74c0fc, var(--ball-11-20)); }
.ball--range-3 { background: linear-gradient(145deg, #ff8787, var(--ball-21-30)); }
.ball--range-4 { background: linear-gradient(145deg, #dee2e6, var(--ball-31-40)); color: #222; }
.ball--range-5 { background: linear-gradient(145deg, #8ce99a, var(--ball-41-45)); }

.ball--bonus {
  background: linear-gradient(145deg, #91c4ff, var(--bonus));
  color: #0a1628;
}

.ball--placeholder {
  background: var(--surface-elevated);
  color: var(--text-muted);
  box-shadow: none;
  animation: none;
}

.bonus-row {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.75rem;
  margin-bottom: 1.25rem;
}

.bonus-label {
  font-size: 0.85rem;
  color: var(--text-muted);
}

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 0.75rem 1.5rem;
  font-family: inherit;
  font-size: 0.95rem;
  font-weight: 600;
  border: none;
  border-radius: 10px;
  cursor: pointer;
  transition: transform 0.15s, box-shadow 0.15s, opacity 0.15s;
}

.btn:active:not(:disabled) {
  transform: scale(0.97);
}

.btn:disabled {
  opacity: 0.55;
  cursor: not-allowed;
}

.btn--primary {
  background: linear-gradient(180deg, #ffe066, var(--accent));
  color: #1a1400;
  box-shadow: 0 4px 20px rgba(245, 197, 66, 0.35);
}

.btn--primary:hover:not(:disabled) {
  box-shadow: 0 6px 28px rgba(245, 197, 66, 0.45);
}

.btn--secondary {
  background: var(--surface-elevated);
  color: var(--text);
  border: 1px solid var(--border);
}

.btn--secondary:hover:not(:disabled) {
  background: #252d3d;
}

.sim-header {
  margin-bottom: 1rem;
}

.sim-desc {
  margin: 0.35rem 0 0;
  font-size: 0.88rem;
  color: var(--text-muted);
}

.controls {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: 0.75rem;
  margin-bottom: 1.25rem;
}

.controls label {
  font-size: 0.9rem;
  color: var(--text-muted);
}

.controls select {
  padding: 0.55rem 0.85rem;
  font-family: inherit;
  font-size: 0.9rem;
  background: var(--surface-elevated);
  color: var(--text);
  border: 1px solid var(--border);
  border-radius: 8px;
  cursor: pointer;
}

.stats {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 0.75rem;
  margin-bottom: 1.25rem;
}

@media (max-width: 520px) {
  .stats {
    grid-template-columns: 1fr;
  }
}

.stat {
  padding: 0.75rem;
  background: var(--surface-elevated);
  border-radius: 10px;
  text-align: center;
}

.stat-label {
  display: block;
  font-size: 0.75rem;
  color: var(--text-muted);
  margin-bottom: 0.25rem;
}

.stat-value {
  font-family: "JetBrains Mono", monospace;
  font-size: 1rem;
  font-weight: 600;
  color: var(--accent);
}

.chart-wrap {
  position: relative;
  width: 100%;
  overflow-x: auto;
  border-radius: 10px;
  background: var(--surface-elevated);
  padding: 0.5rem;
}

#freq-chart {
  display: block;
  width: 100%;
  height: auto;
  min-height: 220px;
}

.chart-legend {
  display: flex;
  flex-wrap: wrap;
  gap: 1rem;
  justify-content: center;
  margin: 0.75rem 0 0;
  font-size: 0.8rem;
  color: var(--text-muted);
}

.legend-bar,
.legend-line {
  display: inline-block;
  width: 1rem;
  height: 0.65rem;
  margin-right: 0.35rem;
  vertical-align: middle;
  border-radius: 2px;
}

.legend-bar {
  background: var(--accent);
}

.legend-line {
  width: 1.25rem;
  height: 0;
  border-top: 2px dashed #ff6b6b;
  border-radius: 0;
}

.loading {
  text-align: center;
  color: var(--accent);
  font-size: 0.9rem;
  margin: 1rem 0 0;
}

.footer {
  text-align: center;
  font-size: 0.8rem;
  color: var(--text-muted);
}

.footer code {
  font-family: "JetBrains Mono", monospace;
  font-size: 0.78rem;
  color: var(--text);
}

const MAX_NUMBER = 45;
const MAIN_COUNT = 6;
const DRAWS_PER_TRIAL = 7; // 6 main + 1 bonus

/** @returns {{ main: number[], bonus: number }} */
function drawLotto() {
  const pool = Array.from({ length: MAX_NUMBER }, (_, i) => i + 1);
  const main = [];

  for (let i = 0; i < MAIN_COUNT; i++) {
    const idx = Math.floor(Math.random() * pool.length);
    main.push(pool.splice(idx, 1)[0]);
  }

  const bonus = pool[Math.floor(Math.random() * pool.length)];
  main.sort((a, b) => a - b);
  return { main, bonus };
}

/** @param {number} n */
function expectedFrequency(n) {
  return (n * DRAWS_PER_TRIAL) / MAX_NUMBER;
}

/**
 * @param {number} n
 * @returns {number[]} frequencies indexed 1..45
 */
function simulate(n) {
  const freq = new Array(MAX_NUMBER + 1).fill(0);

  for (let i = 0; i < n; i++) {
    const { main, bonus } = drawLotto();
    for (const num of main) freq[num]++;
    freq[bonus]++;
  }

  return freq;
}

/** @param {number} num */
function ballRangeClass(num) {
  if (num <= 10) return "ball--range-1";
  if (num <= 20) return "ball--range-2";
  if (num <= 30) return "ball--range-3";
  if (num <= 40) return "ball--range-4";
  return "ball--range-5";
}

/** @param {number} n */
function formatNumber(n) {
  return n.toLocaleString("ko-KR");
}

const mainBallsEl = document.getElementById("main-balls");
const bonusBallEl = document.getElementById("bonus-ball");
const btnDraw = document.getElementById("btn-draw");
const btnSimulate = document.getElementById("btn-simulate");
const trialSelect = document.getElementById("trial-select");
const statsEl = document.getElementById("stats");
const chartWrapEl = document.getElementById("chart-wrap");
const loadingEl = document.getElementById("loading");
const statTrials = document.getElementById("stat-trials");
const statExpected = document.getElementById("stat-expected");
const statDeviation = document.getElementById("stat-deviation");
const canvas = /** @type {HTMLCanvasElement} */ (document.getElementById("freq-chart"));

function renderBall(num, extraClass = "") {
  const el = document.createElement("span");
  el.className = `ball ${ballRangeClass(num)} ${extraClass}`.trim();
  el.textContent = String(num);
  el.setAttribute("aria-label", `번호 ${num}`);
  return el;
}

function showPlaceholders() {
  mainBallsEl.replaceChildren();
  for (let i = 0; i < MAIN_COUNT; i++) {
    const el = document.createElement("span");
    el.className = "ball ball--placeholder";
    el.textContent = "?";
    mainBallsEl.appendChild(el);
  }
  bonusBallEl.hidden = true;
  bonusBallEl.textContent = "?";
}

function renderDraw({ main, bonus }) {
  mainBallsEl.replaceChildren();
  for (const num of main) {
    mainBallsEl.appendChild(renderBall(num));
  }
  bonusBallEl.hidden = false;
  bonusBallEl.textContent = String(bonus);
  bonusBallEl.className = `ball ball--bonus ${ballRangeClass(bonus)}`;
  bonusBallEl.setAttribute("aria-label", `보너스 번호 ${bonus}`);
}

function handleDraw() {
  renderDraw(drawLotto());
}

/**
 * @param {number[]} freq
 * @param {number} expected
 */
function drawChart(freq, expected) {
  const dpr = window.devicePixelRatio || 1;
  const barCount = MAX_NUMBER;
  const barGap = 2;
  const padding = { top: 24, right: 16, bottom: 36, left: 48 };
  const width = Math.max(640, barCount * 14);
  const height = 280;

  canvas.width = width * dpr;
  canvas.height = height * dpr;
  canvas.style.width = `${width}px`;
  canvas.style.height = `${height}px`;

  const ctx = canvas.getContext("2d");
  ctx.scale(dpr, dpr);

  const counts = freq.slice(1);
  const maxCount = Math.max(...counts, expected * 1.15);
  const chartW = width - padding.left - padding.right;
  const chartH = height - padding.top - padding.bottom;
  const barW = (chartW - barGap * (barCount - 1)) / barCount;

  ctx.clearRect(0, 0, width, height);

  // grid
  ctx.strokeStyle = "rgba(255,255,255,0.06)";
  ctx.lineWidth = 1;
  const gridLines = 5;
  for (let i = 0; i <= gridLines; i++) {
    const y = padding.top + (chartH * i) / gridLines;
    ctx.beginPath();
    ctx.moveTo(padding.left, y);
    ctx.lineTo(width - padding.right, y);
    ctx.stroke();
  }

  // expected line
  const expectedY = padding.top + chartH - (expected / maxCount) * chartH;
  ctx.strokeStyle = "#ff6b6b";
  ctx.setLineDash([6, 4]);
  ctx.lineWidth = 2;
  ctx.beginPath();
  ctx.moveTo(padding.left, expectedY);
  ctx.lineTo(width - padding.right, expectedY);
  ctx.stroke();
  ctx.setLineDash([]);

  // bars
  for (let i = 0; i < barCount; i++) {
    const num = i + 1;
    const count = counts[i];
    const barH = (count / maxCount) * chartH;
    const x = padding.left + i * (barW + barGap);
    const y = padding.top + chartH - barH;

    const rangeHue =
      num <= 10 ? "#f5c542" :
      num <= 20 ? "#4dabf7" :
      num <= 30 ? "#ff6b6b" :
      num <= 40 ? "#ced4da" : "#69db7c";

    ctx.fillStyle = rangeHue;
    ctx.globalAlpha = 0.85;
    ctx.fillRect(x, y, barW, barH);
    ctx.globalAlpha = 1;

    if (num % 5 === 0 || num === 1 || num === MAX_NUMBER) {
      ctx.fillStyle = "#8b95a8";
      ctx.font = "10px JetBrains Mono, monospace";
      ctx.textAlign = "center";
      ctx.fillText(String(num), x + barW / 2, height - 12);
    }
  }

  // y-axis label (expected)
  ctx.fillStyle = "#8b95a8";
  ctx.font = "11px Noto Sans KR, sans-serif";
  ctx.textAlign = "right";
  ctx.fillText(formatNumber(Math.round(expected)), padding.left - 8, expectedY + 4);
}

/**
 * @param {number[]} freq
 * @param {number} trials
 */
function updateStats(freq, trials) {
  const expected = expectedFrequency(trials);
  let maxDev = 0;

  for (let i = 1; i <= MAX_NUMBER; i++) {
    const dev = Math.abs(freq[i] - expected);
    if (dev > maxDev) maxDev = dev;
  }

  statTrials.textContent = `${formatNumber(trials)}회`;
  statExpected.textContent = expected.toFixed(1);
  statDeviation.textContent = `±${maxDev.toFixed(0)}`;
}

function runSimulationAsync(trials) {
  btnSimulate.disabled = true;
  btnDraw.disabled = true;
  loadingEl.hidden = false;
  statsEl.hidden = true;
  chartWrapEl.hidden = true;

  const run = () => {
    const freq = simulate(trials);
    const expected = expectedFrequency(trials);
    updateStats(freq, trials);
    drawChart(freq, expected);
    statsEl.hidden = false;
    chartWrapEl.hidden = false;
    loadingEl.hidden = true;
    btnSimulate.disabled = false;
    btnDraw.disabled = false;
  };

  if (trials >= 50000) {
    setTimeout(run, 16);
  } else {
    requestAnimationFrame(run);
  }
}

btnDraw.addEventListener("click", handleDraw);
btnSimulate.addEventListener("click", () => {
  const trials = Number(trialSelect.value);
  runSimulationAsync(trials);
});

showPlaceholders();
handleDraw();
